+    // =========================================================================
+    // Speculative Prefetch API (Strategy 1)
+    // =========================================================================
+
+    /// Hint that this tensor will likely be needed soon
+    /// Loads it into cache if not already present
+    /// This is synchronous in V1 - still helps by loading before GPU needs it
+    /// V2 could use async I/O for true non-blocking prefetch
+    ///
+    /// IMPORTANT: Prefetched entries are NOT protected from eviction.
+    /// If prediction was wrong, they can be evicted to make room for actual requests.
+    pub fn prefetchHint(
+        self: *Self,
+        name: []const u8,
+        data_ptr: [*]const u8,
+        length: usize,
+    ) void {
+        self.prefetch_total += 1;
+
+        // If already cached, count as a hit but DON'T update generation
+        // Let actual getOrLoad call update the generation when the tensor is used
+        if (self.lookup.contains(name)) {
+            self.prefetch_hits += 1;
+            return;
+        }
+
+        // Not in cache - load it now (synchronous prefetch)
+        // This still helps because we load BEFORE the GPU needs it
+        // Use getOrLoadWithoutProtection to avoid marking as current generation
+        _ = self.getOrLoadPrefetch(name, data_ptr, length) catch {
+            // Prefetch failure is non-fatal, just log and continue
+            std.log.debug("Prefetch failed for {s}", .{name});
+        };
+    }
+
+    /// Load tensor for prefetch - same as getOrLoad but marks with PREVIOUS generation
+    /// so these entries can be evicted if the prediction was wrong
+    fn getOrLoadPrefetch(
+        self: *Self,
+        name: []const u8,
+        data_ptr: [*]const u8,
+        length: usize,
+    ) !objc.MTLBuffer {
+        // Check cache first
+        if (self.lookup.get(name)) |entry| {
+            // Already cached - return without updating generation
+            return entry.buffer;
+        }
+
+        // Cache miss - load it
+        self.misses += 1;
+
+        // Check if this is a VIP expert
+        const is_vip = isVipExpert(name);
+
+        // Evict LRU entries until we have space
+        while (self.current_size + length > self.max_size and self.tail != null) {
+            if (!self.evictOneNonPinned()) {
+                std.log.warn("ExpertCache: Cannot evict - all entries pinned! size={d}MB", .{
+                    self.current_size / (1024 * 1024),
+                });
+                break;
+            }
+        }
+
+        // Create resident buffer
+        const buffer = objc.deviceNewBufferWithBytes(
+            self.device,
+            @ptrCast(data_ptr),
+            @intCast(length),
+            objc.MTLResourceStorageModeShared,
+        ) orelse return error.MetalBufferAllocFailed;
+
+        // Create cache entry with PREVIOUS generation (evictable)
+        const key_copy = try self.allocator.dupe(u8, name);
+        errdefer self.allocator.free(key_copy);
+
+        const entry = try self.allocator.create(Entry);
+        // Use generation current-3 so it can be evicted if cache is full
+        // but survives longer than generation=0 entries
+        const prefetch_gen = if (self.current_generation > 3)
+            self.current_generation - 3
+        else
+            0;
+        entry.* = Entry{
+            .key = key_copy,
+            .buffer = buffer,
+            .size = length,
+            .pinned = is_vip,
+            .last_used_generation = prefetch_gen, // Partially protected
+            .prev = null,
+            .next = null,
+        };
+
+        // Add to LRU list (front = most recently used)
+        self.addToFront(entry);
+
+        // Add to lookup map
+        try self.lookup.put(key_copy, entry);
+        self.current_size += length;
+        if (is_vip) {
+            self.pinned_size += length;
+        }
+
+        return buffer;
+    }
